def ensure_dirs():
    """Create assets and output directories if they don't exist."""
    os.makedirs(ASSETS_DIR, exist_ok=True)
    os.makedirs(OUTPUT_DIR, exist_ok=True)


def run_cmd(args, quiet=True):
    """Run a command and return (returncode, stdout, stderr)."""
    kwargs = {}
    if quiet:
        kwargs["stdout"] = subprocess.PIPE
        kwargs["stderr"] = subprocess.PIPE
    result = subprocess.run(args, **kwargs)
    stdout = result.stdout.decode("utf-8", errors="replace") if result.stdout else ""
    stderr = result.stderr.decode("utf-8", errors="replace") if result.stderr else ""
    return result.returncode, stdout, stderr


def generate_input(level):
    """Generate synthetic input for a level using FFmpeg lavfi sources."""
    input_gen = level["input_gen"]
    if os.path.exists(input_gen["output"]):
        return True
    rc, _, stderr = run_cmd(input_gen["args"])
    if rc != 0:
        print(f"  ERROR generating input: {stderr}")
        return False
    return True


def run_filtergraph(level, filtergraph):
    """Run the user's filtergraph through FFmpeg."""
    template = level["ffmpeg_template"]
    cmd = []
    for arg in template:
        if "{filtergraph}" in arg:
            cmd.append(arg.replace("{filtergraph}", filtergraph))
        else:
            cmd.append(arg)
    rc, stdout, stderr = run_cmd(cmd)
    if rc != 0:
        return False, stderr
    return True, ""


def probe_output(output_file, stream_type):
    """Use ffprobe to get stream properties as JSON."""
    cmd = [
        "ffprobe", "-v", "quiet",
        "-print_format", "json",
        "-show_streams", "-show_format",
        output_file
    ]
    rc, stdout, stderr = run_cmd(cmd)
    if rc != 0:
        return None
    try:
        data = json.loads(stdout)
    except json.JSONDecodeError:
        return None
    # Find the relevant stream
    for stream in data.get("streams", []):
        if stream.get("codec_type") == stream_type:
            # Also include format-level data
            stream["_format"] = data.get("format", {})
            return stream
    return None


def validate_output(level):
    """Validate the output file against level requirements."""
    output_file = level["output_file"]
    validation = level["validation"]

    if not os.path.exists(output_file):
        return False, "Output file does not exist"

    stream = probe_output(output_file, validation["stream_type"])
    if stream is None:
        return False, "Could not probe output file"

    checks = validation["checks"]
    for key, expected in checks.items():
        if key == "duration_range":
            # Check duration within a range
            duration = None
            # Try stream duration first, then format duration
            if "duration" in stream and stream["duration"] != "N/A":
                duration = float(stream["duration"])
            elif "_format" in stream and "duration" in stream["_format"]:
                duration = float(stream["_format"]["duration"])
            if duration is None:
                return False, "Could not determine duration"
            min_dur, max_dur = expected
            if not (min_dur <= duration <= max_dur):
                return False, f"Duration {duration:.2f}s not in range [{min_dur}, {max_dur}]"
        elif key == "pix_fmt":
            actual = stream.get("pix_fmt", "")
            if actual != expected:
                return False, f"Pixel format: expected '{expected}', got '{actual}'"
        elif key == "width":
            actual = int(stream.get("width", 0))
            if actual != expected:
                return False, f"Width: expected {expected}, got {actual}"
        elif key == "height":
            actual = int(stream.get("height", 0))
            if actual != expected:
                return False, f"Height: expected {expected}, got {actual}"
        else:
            actual = stream.get(key)
            if str(actual) != str(expected):
                return False, f"{key}: expected '{expected}', got '{actual}'"

    return True, "All checks passed"


def run_level(level, filtergraph, verbose=True):
    """Run a single level with the given filtergraph. Returns (passed, details)."""
    # Generate input
    if not generate_input(level):
        return False, "Failed to generate input"

    # Run filtergraph
    success, error = run_filtergraph(level, filtergraph)
    if not success:
        if verbose:
            print(f"  FFmpeg error: {error[:200]}")
        return False, "FFmpeg failed"

    # Validate output
    passed, details = validate_output(level)
    return passed, details


def auto_solve():
    """Run all levels with known correct solutions."""
    ensure_dirs()
    manifest = []
    total_score = 0
    total_possible = len(LEVELS) * 10

    for level in LEVELS:
        print(f"Level {level['number']}: {level['name']}")
        passed, details = run_level(level, level["solution"], verbose=True)

        if passed:
            print("  PASS")
            total_score += 10
        else:
            print(f"  FAIL - {details}")

        manifest.append({
            "level": level["number"],
            "filename": os.path.basename(level["output_file"]),
            "valid": passed
        })

    print(f"\nScore: {total_score}/{total_possible}")

    # Write manifest
    with open(MANIFEST_PATH, "w") as f:
        json.dump(manifest, f, indent=2)
    print(f"Manifest written to {MANIFEST_PATH}")


def interactive():
    """Run the game in interactive mode."""
    ensure_dirs()
    total_score = 0
    total_possible = len(LEVELS) * 10

    print("="*60)
    print("  FFmpeg Filtergraph Puzzle Game")
    print("="*60)
    print()
    print("Solve each level by entering the correct FFmpeg filtergraph.")
    print("Type 'skip' to skip a level, 'quit' to exit.\n")

    for level in LEVELS:
        print(f"--- Level {level['number']}: {level['name']} ---")
        print(level["description"])
        print()

        # Generate input
        if not generate_input(level):
            print("  ERROR: Could not generate input. Skipping.\n")
            continue

        while True:
            try:
                answer = input("Your filtergraph> ").strip()
            except (EOFError, KeyboardInterrupt):
                print("\nExiting.")
                return

            if answer.lower() == "quit":
                print("\nExiting.")
                print(f"Final Score: {total_score}/{total_possible}")
                return
            if answer.lower() == "skip":
                print("  Skipped.\n")
                break
            if not answer:
                continue

            passed, details = run_level(level, answer, verbose=True)
            if passed:
                print("  PASS! Well done!\n")
                total_score += 10
                break
            else:
                print(f"  FAIL - {details}")
                print("  Try again or type 'skip' to move on.\n")

    print(f"\nScore: {total_score}/{total_possible}")


def main():
    parser = argparse.ArgumentParser(description="FFmpeg Filtergraph Puzzle Game")
