                print("  Try again or type 'skip' to move on.\n")

    print(f"\nScore: {total_score}/{total_possible}")


def main():
    parser = argparse.ArgumentParser(description="FFmpeg Filtergraph Puzzle Game")
    parser.add_argument(
        "--auto-solve", action="store_true",
        help="Run all levels with known correct solutions"
    )
    args = parser.parse_args()

    if args.auto_solve:
        auto_solve()
    else:
        interactive()


